export const routes = {
  aboutUs: "About us",
  services: "Services",
  ourCompany: "About the company",
  portfolio: "Portfolio",
  contacts: "Contacts",
};

export const routesEN = [
  {
    name: "About us",
    path: routes.aboutUs,
  },
  {
    name: "Services",
    path: routes.services,
  },
  {
    name: "About the company",
    path: routes.ourCompany,
  },
  {
    name: "Portfolio",
    path: routes.portfolio,
  },
  {
    name: "Contacts",
    path: routes.contacts,
  },
];
